<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***BaseModelClass-PartofMVCArchitecture*Allmodelsshouldextendthisclass*/abstractclassModel{protected$db;protected$table;protected$primaryKey='id';protected$fillable=[];protected$hidden=['password','is_deleted'];publicfunction__construct(){$this->db=Database::getInstance();}/***FindrecordbyID*/publicfunctionfind($id){$sql="SELECT*FROM{$this->table}WHERE{$this->primaryKey}=:idANDis_deleted=falseLIMIT1";return$this->db->fetchOne($sql,['id'=>$id]);}/***Getallrecords*/publicfunctionall($limit=1000,$offset=0){$sql="SELECT*FROM{$this->table}WHEREis_deleted=falseLIMIT:limitOFFSET:offset";return$this->db->fetchAll($sql,['limit'=>$limit,'offset'=>$offset]);}/***Createnewrecord*/publicfunctioncreate($data){/Filteronlyfillablefields$filteredData=array_intersect_key($data,array_flip($this->fillable));/Addtimestamps$filteredData['created_at']=date('Y-m-dH:i:s');$filteredData['updated_at']=date('Y-m-dH:i:s');return$this->db->insert($this->table,$filteredData);}/***Updaterecord*/publicfunctionupdate($id,$data){$filteredData=array_intersect_key($data,array_flip($this->fillable));$filteredData['updated_at']=date('Y-m-dH:i:s');return$this->db->update($this->table,$filteredData,"{$this->primaryKey}=:idANDis_deleted=false",['id'=>$id]);}/***Deleterecord(softdelete)*/publicfunctiondelete($id){return$this->db->softDelete($this->table,"{$this->primaryKey}=:id",['id'=>$id]);}/***Harddeleterecord*/publicfunctionforceDelete($id){return$this->db->delete($this->table,"{$this->primaryKey}=:id",['id'=>$id]);}/***Findbyspecificcolumn*/publicfunctionfindBy($column,$value,$limit=100){$sql="SELECT*FROM{$this->table}WHERE{$column}=:valueANDis_deleted=falseLIMIT:limit";return$this->db->fetchAll($sql,['value'=>$value,'limit'=>$limit]);}/***Countrecords*/publicfunctioncount($conditions=[]){$where="is_deleted=false";$params=[];forforeach($conditionsas$column=>$value){$where.="AND{$column}=:{$column}";$params[$column]=$value;}$sql="SELECTCOUNT(*)astotalFROM{$this->table}WHERE{$where}";$result=$this->db->fetchOne($sql,$params);return$result?(int)$result['total']:0;}/***Paginateresults*/publicfunctionpaginate($page=1,$perPage=20,$conditions=[]){$offset=($page-1)*$perPage;$where="is_deleted=false";$params=[];forforeach($conditionsas$column=>$value){$where.="AND{$column}=:{$column}";$params[$column]=$value;}$sql="SELECT*FROM{$this->table}WHERE{$where}LIMIT:limitOFFSET:offset";$params['limit']=$perPage;$params['offset']=$offset;$data=$this->db->fetchAll($sql,$params);$total=$this->count($conditions);return['data'=>$data,'pagination'=>['current_page'=>$page,'per_page'=>$perPage,'total'=>$total,'total_pages'=>ceil($total/$perPage),'has_next'=>$page<ceil($total/$perPage),'has_prev'=>$page>1]];}/***Executecustomquery*/protectedfunctionquery($sql,$params=[]){return$this->db->fetchAll($sql,$params);}/***Begintransaction*/protectedfunctionbeginTransaction(){return$this->db->beginTransaction();}/***Committransaction*/protectedfunctioncommit(){return$this->db->commit();}/***Rollbacktransaction*/protectedfunctionrollback(){return$this->db->rollback();}}?>
